  name: string;
  deviceId: string;
  hostName?: string | null;
  runtimes?: string[] | null;
  lastSeenAt?: number | null;
  createdAt?: string;
  online: boolean;
};

type RelayMessage =
  | { type: "auth-ok" }
  | {
      deviceId: string;
      hostName?: string;
      online: boolean;
      runtimes?: string[];
      type: "device-status";
    }
  | { command: string; commandId: string; startedAt: string; type: "command-started" }
  | { chunk: string; commandId: string; stream: "stdout" | "stderr"; type: "command-output" }
  | { commandId: string; exitCode: number; finishedAt: string; type: "command-exit" }
  | { error: string; type: "error" };

type RemoteShellProps = {
  userName: string;
  userEmail: string;
};

type AddMachineStep = "form" | "waiting" | "connected";

