            ) : (
              "—"
            )}
          </InfoBlock>
          <InfoBlock label="Created">{createdDate}</InfoBlock>
        </div>

        <div className="flex flex-col gap-3">
          <h2 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">
            Connect Command
          </h2>
          {connectCommand ? (
            <>
              <div className="relative rounded-lg bg-zinc-950 p-4">
                <code className="block text-xs font-mono text-green-400 break-all pr-10 leading-relaxed">
                  {connectCommand}
                </code>
                <button
                  onClick={handleCopy}
                  className="absolute top-3 right-3 p-1.5 rounded hover:bg-white/10 text-zinc-400 hover:text-white transition-colors"
                >
                  {copied ? (
                    <IconCheck className="size-4" />
                  ) : (
                    <IconCopy className="size-4" />
                  )}
                </button>
              </div>
              <p className="text-xs text-muted-foreground">
                Keep this process running — it maintains the connection between your machine and the
                server.
              </p>
            </>
          ) : (
            <div className="flex items-center gap-3 rounded-lg border border-dashed p-4 text-sm text-muted-foreground">
              <span>API key is hidden for security.</span>
              <Button size="sm" variant="outline" onClick={onRotateKey}>
                Rotate &amp; Reveal Key
              </Button>
