                  </div>
                  <form className="flex gap-3" onSubmit={handleRunCommand}>
                    <Input
                      className="font-mono"
                      value={command}
                      onChange={(e) => setCommand(e.target.value)}
                      placeholder="bash command"
                    />
                    <Button
                      disabled={!deviceOnline || !relayConnected || isRunning || !session}
                      type="submit"
                    >
                      {isRunning ? "Running..." : "Run"}
                    </Button>
                  </form>
                  <Textarea className="min-h-64 font-mono text-xs" readOnly value={output} />
                </div>
              </div>
            )}
          </main>
        )}
      </SidebarInset>

      <Dialog
        open={addMachineOpen}
        onOpenChange={(open) => {
          if (!open) handleAddMachineClose();
        }}
      >
