            <DialogTitle>Add Machine</DialogTitle>
          </DialogHeader>

          {newMachineStep === "form" ? (
            <div className="flex flex-col gap-4 py-2">
              <div className="flex flex-col gap-1.5">
                <label className="text-sm font-medium">Machine name</label>
                <Input
