                  onKeyDown={(e) => {
                    if (e.key === "Enter" && !isCreatingMachine) void handleCreateMachine();
                  }}
                />
              </div>
              <Button
                disabled={isCreatingMachine}
                onClick={() => void handleCreateMachine()}
              >
                {isCreatingMachine ? "Creating..." : "Create Machine"}
